88	export interface ClaimResult {
89	  payout: number;
90	  remainingCap: number;
91	}
92	
93	const INSURANCE_VALUES: Record<string, number> = {
94	  sword: 1000,
95	  amulet: 600,
96	  staff: 800,
97	  potion: 400,
98	  rune: 250,
99	  moonstone: 250,
100	};
101	const DEDUCTIBLE = 100;
102	const CAP_MULTIPLIER = 2;
103	const HIGH_ENCHANT_DAMAGE_THRESHOLD = 8;
104	const HIGH_ENCHANT_DAMAGE_DIVISOR = 2;
105	
106	// Reimbursable amount for a single damage entry, before the per-event deductible.
107	// High-enchantment items (enchantment >= 8) are reimbursed at 50% of damage.
108	function reimbursableAmount(policy: Policy, damage: Damage): number {
109	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
110	  const isHighEnchant = (damagedItem?.enchantment ?? 0) >= HIGH_ENCHANT_DAMAGE_THRESHOLD;
111	  return isHighEnchant ? damage.amount / HIGH_ENCHANT_DAMAGE_DIVISOR : damage.amount;
112	}
113	
114	export function claim(policy: Policy, incident: Incident, _remainingCap: number): ClaimResult {
115	  const payout = incident.damages.reduce(
116	    (sum, damage) => sum + reimbursableAmount(policy, damage) - DEDUCTIBLE,
117	    0,
118	  );
119	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
120	  const remainingCap = CAP_MULTIPLIER * insuranceSum - payout;
121	  return { payout, remainingCap };
122	}
123	
124	export function quote(customer: Customer, items: Item[], options?: QuoteOptions): number {
125	  const baseTotal = policyBaseTotal(items);
126	  const surchargeTotal = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
127	  const firstInsurance = baseTotal * FIRST_INSURANCE_RATE;
128	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT : 0;
129	  const followUpDiscount = options?.isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
130	  const premium =
131	    baseTotal + surchargeTotal + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
132	  return Math.ceil(premium);
133	}
